+ */
+function declarationsIn(text: string, selectorRegex: RegExp): string | null {
   const re = new RegExp(selectorRegex.source + '\\s*\\{([^}]*)\\}');
-  const m = CSS.match(re);
+  const m = text.match(re);
   return m ? m[1] : null;
 }

+function ruleDeclarations(selectorRegex: RegExp): string | null {
+  return declarationsIn(CSS, selectorRegex);
+}
+
+/**
+ * Extract the body of the FIRST `@media` rule whose media-condition targets
+ * coarse-pointer / touch devices — i.e. references `(hover: none)` and/or
+ * `(pointer: coarse)` — correctly handling the nested `{ ... }` rule blocks
+ * inside a media query (a naive "stop at the first `}`" parse returns only a
+ * fragment). Returns null if no such rule exists.
+ *
+ * Whitespace inside the condition is normalized before matching, so both
+ * `(hover: none)` and `(hover:none)` (and likewise for `pointer: coarse`) are
+ * accepted. The vitest environment does not load app.css and does not set any
+ * emulated media features, so this text-parsing approach is the only way to
+ * observe an `@media` rule.
+ */
+function coarsePointerMediaQueryBody(): string | null {
+  const mediaRe = /@media\s+([^{}]*)\{/g;
+  let m: RegExpExecArray | null;
+  while ((m = mediaRe.exec(CSS)) !== null) {
+    const condition = m[1].replace(/\s+/g, '');
+    const targetsTouch = condition.includes('hover:none') || condition.includes('pointer:coarse');
+    if (!targetsTouch) continue;
+    const start = m.index! + m[0].length;
+    let depth = 1;
+    let i = start;
+    while (i < CSS.length && depth > 0) {
+      if (CSS[i] === '{') depth++;
+      else if (CSS[i] === '}') depth--;
+      i++;
+    }
+    if (depth !== 0) return null; // unbalanced braces — treat as not found
+    return CSS.slice(start, i - 1);
+  }
+  return null;
+}
+
+/**
+ * Returns the full selector list (the text between the previous rule's closing
+ * `}` and the opening `{`) of the REVEAL rule — the grouped rule whose
+ * declaration block sets `opacity:1` and `pointer-events:auto`. Returns the
+ * empty string if no such rule exists.
+ *
+ * Used to verify WHICH selectors participate in the `.row-menu-btn` reveal
+ * (hover / keyboard-focus / aria-expanded) without depending on the exact
+ * quote style of `[aria-expanded]`.
+ */
+function revealSelectorList(): string {
+  const m = CSS.match(/opacity\s*:\s*1\s*;[\s\S]*?pointer-events\s*:\s*auto\s*;/);
+  if (!m || m.index === undefined) return '';
+  const upToDecl = CSS.slice(0, m.index);
+  const openBrace = upToDecl.lastIndexOf('{');
+  const prevClose = upToDecl.lastIndexOf('}', openBrace);
+  return CSS.slice(prevClose + 1, openBrace);
+}
+
+/**
+ * Returns the body (text between the outer `{` … `}`) of the FIRST
+ * `@media (hover: none) { … }` block, or the empty string if none exists.
+ * Brace-balanced so nested rules inside the media block are captured.
+ *
+ * Touch devices have no `:hover`, so the `.row-menu-btn` hover-based reveal is
+ * unreachable there unless an author `@media (hover: none)` override (or a
+ * non-zero base opacity) makes the trigger perceivable & operable.
+ */
+function mediaHoverNoneBody(): string {
+  const open = CSS.search(/@media[^{]*\(\s*hover\s*:\s*none\s*\)[^{]*\{/);
+  if (open < 0) return '';
+  const braceIdx = CSS.indexOf('{', open);
+  if (braceIdx < 0) return '';
+  let i = braceIdx + 1;
+  let depth = 1;
+  let body = '';
+  while (i < CSS.length && depth > 0) {
+    const ch = CSS[i];
+    if (ch === '{') depth++;
+    else if (ch === '}') depth--;
+    if (depth > 0) body += ch;
+    i++;
+  }
+  return body;
+}
+
 describe('src/app.css — native <dialog> visibility contract', () => {
   it('the base .browser-dialog rule does NOT declare display', () => {
     // Selector must be exactly `.browser-dialog` followed by `{` — the negative
@@ -249,16 +342,25 @@ describe('src/app.css — row action "⋮" button (.row-menu-btn)', () => {
     expect(/padding\s*:\s*\d+px/.test(btn!), 'padding present').toBe(true);
   });

-  it('is hidden and non-interactive by default (revealed only on hover/open)', () => {
+  it('is initially suppressed (low opacity, non-interactive) by default', () => {
+    // The base rule keeps the trigger quiet until the row is hovered/focused or
+    // its menu is open: `pointer-events:none` stops it capturing clicks while
